def authenticate_user(username, password):
    """Authenticate user against the internal user store."""
    user = USER_STORE.get(username)
    if user and user["password"] == password:
        return user
    return None


def get_sp_name(sp_entity_id):
    """Get the display name for a registered SP."""
    sp = SP_REGISTRY.get(sp_entity_id)
    return sp["name"] if sp else None


