@app.route("/admin/sp", methods=["GET"])
def admin_sp_list():
    """Admin endpoint to list registered SPs (protected)."""
    if "username" not in session:
        return redirect("/")

    user = USER_STORE.get(session["username"])
    if not user or "admin" not in user.get("roles", []):
        return "Forbidden", 403

    return {"service_providers": SP_REGISTRY}


@app.route("/health")
def health():
    """Health check endpoint."""
    return {"status": "healthy", "idp_entity_id": IDP_CONFIG["entity_id"]}


# --- IdP-Initiated SSO ---

@app.route("/idp-init/<sp_id>")
def idp_initiated_sso(sp_id):
    """IdP-initiated SSO for a specific SP."""
    # Find SP by a simple identifier
    target_sp = None
    target_sp_entity_id = None

    for entity_id, sp_config in SP_REGISTRY.items():
        if sp_id in entity_id or sp_id == sp_config.get("name", "").lower().replace(" ", "-"):
            target_sp = sp_config
            target_sp_entity_id = entity_id
            break

    if not target_sp:
        return "Unknown Service Provider", 404

    if "username" not in session:
        return redirect("/")

    username = session["username"]
    user_info = USER_STORE.get(username)

    if not user_info:
        session.clear()
        return redirect("/")

    # Create a synthetic AuthnRequest
    authn_request = {
        "id": _generate_id(),
        "issuer": target_sp_entity_id,
        "acs_url": target_sp["acs_url"],
    }

    return _generate_and_send_response(authn_request, user_info, username, "")


def create_ssl_context():
    """Create SSL context for HTTPS."""
    ssl_context = ssl.SSLContext(ssl.PROTOCOL_TLS_SERVER)

    cert_file = IDP_CONFIG["certificate_file"]
    key_file = IDP_CONFIG["private_key_file"]

    # Generate certs if they don't exist
    if not os.path.exists(cert_file) or not os.path.exists(key_file):
        _generate_self_signed_cert_and_key()

    ssl_context.load_cert_chain(cert_file, key_file)
    ssl_context.minimum_version = ssl.TLSVersion.TLSv1_2
    return ssl_context


if __name__ == "__main__":
    import logging

    logging.basicConfig(level=logging.INFO)
    logger = logging.getLogger(__name__)

    # Ensure certificates exist
    if not os.path.exists(IDP_CONFIG["certificate_file"]) or \
       not os.path.exists(IDP_CONFIG["private_key_file"]):
        logger.info("Generating self-signed certificate and key...")
        _generate_self_signed_cert_and_key()
        logger.info("Certificate and key generated.")

    logger.info(f"Starting Internal SAML IdP")
    logger.info(f"Entity ID: {IDP_CONFIG['entity_id']}")
    logger.info(f"SSO URL: {IDP_CONFIG['sso_url']}")
    logger.info(f"Metadata URL: https://localhost:8443/metadata")
    logger.info(f"Registered SPs: {len(SP_REGISTRY)}")
    logger.info("NOTE: Assertions are signed but not encrypted. HTTPS provides transport security.")

    ssl_ctx = create_ssl_context()

    app.run(
        host="0.0.0.0",
        port=8443,
        ssl_context=ssl_ctx,
        debug=False,
    )